mepc_setup:       
                  la x7, init
                  csrw 0x341, x7

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_machine_mode:
                  li x7, 0x4d4018b6
                  csrw 0x300, x7 # MSTATUS
                  li x7, 0x75d96bff
                  csrw 0x304, x7 # MIE
                  li x25, 0x8ffffffc
                  li x7, 0x300
                  slli x7, x7, 8
                  addi x7, x7, 0x3
                  sw x7, 0(x25)
                  csrr x7, 0x300
                  sw x7, 0(x25)
                  li x25, 0x8ffffffc
                  li x7, 0x304
                  slli x7, x7, 8
                  addi x7, x7, 0x3
                  sw x7, 0(x25)
                  csrr x7, 0x304
                  sw x7, 0(x25)
                  mret
init:             
                  li x0, 0x80000000
                  li x1, 0x80000000
                  li x2, 0xf63ce95a
                  li x3, 0xf6f6fb92
                  li x4, 0xfcbe7875
                  li x5, 0xf137f929
                  li x6, 0x4
                  li x7, 0x6
                  li x8, 0x80000000
                  li x9, 0x0
                  li x10, 0x80000000
                  li x11, 0x80000000
                  li x13, 0x0
                  li x14, 0xc5d0fb96
                  li x15, 0x8f4afea
                  li x16, 0x0
                  li x17, 0xf2d2599a
                  li x18, 0xf04f5515
                  li x19, 0x4
                  li x20, 0x80000000
                  li x21, 0x0
                  li x22, 0xf9d9f3d9
                  li x23, 0x80000000
                  li x24, 0xf0a96ddf
                  li x25, 0xf4cc2bcf
                  li x26, 0x0
                  li x27, 0xf8831ce3
                  li x29, 0x0
                  li x30, 0xfc6da9b3
                  li x31, 0x80000000
                  la x28, user_stack_end
                  li x25, 0x8ffffffc
                  li x7, 0x0
                  slli x7, x7, 8
                  addi x7, x7, 0x0
                  sw x7, 0(x25)
                  j main
test_done:        
                  li x25, 0x8ffffff8
                  li x7, 0x0
                  slli x7, x7, 8
                  addi x7, x7, 0x1
                  sw x7, 0(x25)
                  ecall

test_fail:        
                  li x25, 0x8ffffff8
                  li x7, 0x1
                  slli x7, x7, 8
                  addi x7, x7, 0x1
                  sw x7, 0(x25)
                  ecall

